import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Spin,
  Statistic,
} from '@/components/common';
import { fpcService } from '../../../services/fpc/service';
import type { ProjectedBalanceSheetDto } from '../../../services/fpc/types';
import styles from './ProjectedBalanceSheetPage.module.css';

const SIDE_COLORS: Record<string, string> = {
  Asset: '#1677ff',
  Liability: '#fa8c16',
  Equity: '#52c41a',
};

const SIDE_LABELS: Record<string, string> = {
  Asset: 'Tài sản',
  Liability: 'Nợ phải trả',
  Equity: 'Vốn chủ sở hữu',
};

export default function ProjectedBalanceSheetPage() {
  const [data, setData] = useState<ProjectedBalanceSheetDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [projectMonths, setProjectMonths] = useState(12);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fpcService.getProjectedBs({ projectMonths });
      setData(result);
    } finally {
      setLoading(false);
    }
  }, [projectMonths]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const formatMoney = (v: number) =>
    new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v);

  return (
    <div className={styles.page}>
      <Title level={3}>Bảng cân đối kế toán dự phóng</Title>

      <Card style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <span>Số tháng dự phóng: </span>
          <input
            type="number"
            min={1}
            max={60}
            value={projectMonths}
            onChange={(e) => {
              const v = parseInt(e.target.value, 10);
              if (!isNaN(v)) setProjectMonths(v);
            }}
            style={{ width: 80 }}
          />
        </div>
      </Card>

      {loading ? (
        <Spin size="large" style={{ display: 'block', margin: '80px auto' }} />
      ) : data ? (
        <>
          <div style={{ display: 'flex', gap: 16, marginBottom: 16 }}>
            <div style={{ flex: 1 }}>
              <Card>
                <Statistic
                  title="Tổng tài sản"
                  value={data.totalAssets}
                  formatter={(v) => formatMoney(Number(v))}
                  valueStyle={{ color: '#1677ff' }}
                />
              </Card>
            </div>
            <div style={{ flex: 1 }}>
              <Card>
                <Statistic
                  title="Tổng nợ phải trả"
                  value={data.totalLiabilities}
                  formatter={(v) => formatMoney(Number(v))}
                  valueStyle={{ color: '#cf1322' }}
                />
              </Card>
            </div>
            <div style={{ flex: 1 }}>
              <Card>
                <Statistic
                  title="Vốn chủ sở hữu"
                  value={data.totalEquity}
                  formatter={(v) => formatMoney(Number(v))}
                  valueStyle={{ color: '#3f8600' }}
                />
              </Card>
            </div>
          </div>

          <table className={styles.table}>
            <thead>
              <tr>
                <th style={{ width: 240 }}>Khoản mục</th>
                <th style={{ width: 100 }}>Loại</th>
                <th style={{ textAlign: 'right' }}>Số dư hiện tại</th>
                <th style={{ textAlign: 'right' }}>Dự phóng</th>
                <th style={{ textAlign: 'right' }}>Thay đổi</th>
                <th style={{ width: 300 }}>Ghi chú</th>
              </tr>
            </thead>
            <tbody>
              {data.rows.map((row) => (
                <tr key={row.categoryCode}>
                  <td>{row.categoryName}</td>
                  <td>
                    <Tag color={SIDE_COLORS[row.side] || undefined}>
                      {SIDE_LABELS[row.side] || row.side}
                    </Tag>
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    {formatMoney(row.currentBalance)}
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    <Text strong>{formatMoney(row.projectedBalance)}</Text>
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    <Text type={row.change >= 0 ? 'success' : 'danger'}>
                      {formatMoney(row.change)}
                    </Text>
                  </td>
                  <td>{row.notes}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      ) : null}
    </div>
  );
}
